@page "/chat"
@rendermode InteractiveServer
@using sv_0885e901e23f443b9f775c7f807c40f6.Models
@using sv_0885e901e23f443b9f775c7f807c40f6.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout">
    @* ─── Left sidebar: channel list ─── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h5>Channels</h5>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var ch in _channels)
                {
                    <li class="channel-item @(ch.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@Truncate(ch.Description, 40)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ─── Main message area ─── *@
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h5># @_activeChannel.Name</h5>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScrollAsync">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-content-wrapper">
                                <div class="message-meta">
                                    <strong class="author">@msg.Author</strong>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-body">@msg.Content</div>

                                @* Reactions *@
                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reactions-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                    @onclick="() => AddReactionAsync(msg.Id, r.Emoji)">
                                                @r.Emoji @r.Users.Count
                                            </button>
                                        }
                                    </div>
                                }

                                @* Thread starter link *@
                                @if (_threadSummaries.TryGetValue(msg.Id, out var ts))
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                        💬 @ts.ReplyCount @(ts.ReplyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @* Hover actions *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg.Id)">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😀 React
                                        </button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessage" @bind:event="oninput"
                          placeholder="Type a message…"
                          @onkeydown="OnMessageKeyDownAsync"
                          rows="2"></textarea>
                <button class="btn-send" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessage)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ─── Right panel: thread view ─── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h6>Thread</h6>
                <button class="close-btn" @onclick="CloseThread">✕</button>
            </div>

            <div class="thread-root-quote">
                <strong>@_threadRootMessage.Author</strong>
                <span class="timestamp">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="thread-reply">
                            <div class="message-meta">
                                <strong class="author">@reply.Author</strong>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-body">@reply.Content</div>
                        </div>
                    }
                }
            </div>

            <div class="thread-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          placeholder="Reply in thread…"
                          @onkeydown="OnThreadKeyDownAsync"
                          rows="2"></textarea>
                <button class="btn-send" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    // ─── State ───
    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private string _newMessage = "";
    private bool _loadingOlder;
    private bool _hasMoreMessages = true;
    private const int PageSize = 30;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = "";

    private ElementReference _messageListRef;

    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // ─── Lifecycle ───
    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    // ─── Channel selection ───
    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messages = null;
        _hasMoreMessages = true;
        _threadSummaries.Clear();

        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count == PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to clear unread badge
        _channels = await ChatService.GetChannelsAsync();

        await ScrollToBottomAsync();
    }

    // ─── Messaging ───
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null)
            return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _newMessage = "";

        _messages ??= new();
        _messages.Add(sent);

        await ScrollToBottomAsync();
    }

    private async Task OnMessageKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ─── Pagination ───
    private async Task OnMessageListScrollAsync()
    {
        if (_loadingOlder || !_hasMoreMessages || _activeChannelId is null || _messages is null)
            return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50)
            return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }
        _hasMoreMessages = older.Count == PageSize;
        _loadingOlder = false;
    }

    // ─── Reactions ───
    private async Task AddReactionAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to show updated reactions
        if (_activeChannelId is not null && _messages is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
            _messages = refreshed;
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    // ─── Thread ───
    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadReplyText = "";
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(
            _activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplyText = "";

        _threadReplies ??= new();
        _threadReplies.Add(reply);

        // Update thread summary in main view
        BuildThreadSummaries();
    }

    private async Task OnThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ─── Helpers ───
    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        _threadSummaries.Clear();
        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key, group.Count(), group.Max(m => m.SentAt));
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLen)
        => text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }
}

