toolArgs.file_text:
::deep .chat-layout {
    display: flex;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
    overflow: hidden;
}

/* ─── Sidebar ─── */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #522653;
}

::deep .sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #522653;
}

::deep .sidebar-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
}

::deep .channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

::deep .channel-item.active {
    background: #1164a3;
    color: #fff;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .channel-desc {
    font-size: 0.75rem;
    opacity: 0.7;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 20px;
    text-align: center;
}

/* ─── Main message area ─── */
::deep .message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.2s ease;
}

::deep .message-area.expanded {
    width: 80%;
}

::deep .message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

::deep .message-header h5 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
}

::deep .channel-description {
    font-size: 0.82rem;
    color: #616061;
    margin-top: 2px;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

::deep .loading-indicator {
    text-align: center;
    color: #888;
    padding: 8px;
    font-size: 0.85rem;
}

::deep .message-row {
    display: flex;
    align-items: flex-start;
    padding: 6px 8px;
    border-radius: 6px;
    position: relative;
    transition: background 0.1s;
}

::deep .message-row:hover {
    background: #f8f8f8;
}

::deep .message-content-wrapper {
    flex: 1;
    min-width: 0;
}

::deep .message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .author {
    font-size: 0.95rem;
}

::deep .timestamp {
    font-size: 0.75rem;
    color: #888;
}

::deep .message-body {
    font-size: 0.93rem;
    line-height: 1.45;
    word-break: break-word;
}

/* Reactions */
::deep .reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

::deep .reaction-badge {
    background: #f0f4ff;
    border: 1px solid #d0d8ea;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

::deep .reaction-badge:hover {
    background: #dde5f7;
}

/* Thread link */
::deep .thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.82rem;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
    font-weight: 600;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* Hover actions */
::deep .message-actions {
    display: flex;
    gap: 4px;
    position: absolute;
    right: 8px;
    top: 4px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

::deep .action-btn {
    background: none;
    border: none;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    white-space: nowrap;
}

::deep .action-btn:hover {
    background: #f0f0f0;
}

/* Emoji picker */
::deep .emoji-picker-wrapper {
    position: relative;
}

::deep .emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 20;
}

::deep .emoji-option {
    background: none;
    border: none;
    font-size: 1.3rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

::deep .emoji-option:hover {
    background: #f0f0f0;
}

/* Message input */
::deep .message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e8e8e8;
    background: #fff;
    flex-shrink: 0;
}

::deep .message-input-area textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

::deep .message-input-area textarea:focus {
    border-color: #1264a3;
}

::deep .btn-send {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 20px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s;
    align-self: flex-end;
}

::deep .btn-send:hover:not(:disabled) {
    background: #006048;
}

::deep .btn-send:disabled {
    opacity: 0.5;
    cursor: default;
}

::deep .no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #888;
    font-size: 1.1rem;
}

/* ─── Thread panel ─── */
::deep .thread-panel {
    width: 25%;
    min-width: 280px;
    background: #fff;
    border-left: 1px solid #e8e8e8;
    display: flex;
    flex-direction: column;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

::deep .thread-header h6 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

::deep .close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 4px;
    color: #666;
}

::deep .close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

::deep .thread-root-quote {
    padding: 12px 16px;
    background: #fafafa;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

::deep .thread-root-quote strong {
    font-size: 0.9rem;
}

::deep .thread-root-quote .timestamp {
    font-size: 0.75rem;
    color: #888;
    margin-left: 8px;
}

::deep .thread-root-quote p {
    margin: 4px 0 0;
    font-size: 0.9rem;
    color: #333;
}

::deep .thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
}

::deep .thread-reply {
    padding: 6px 0;
    border-bottom: 1px solid #f0f0f0;
}

::deep .thread-reply:last-child {
    border-bottom: none;
}

::deep .thread-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e8e8e8;
    background: #fff;
    flex-shrink: 0;
}

::deep .thread-input-area textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

::deep .thread-input-area textarea:focus {
    border-color: #1264a3;
}

